'use client'

import { useEffect, useRef, useState } from 'react'
import { PageLayout, StorySection } from '@/components/layout'

const STORY_SECTIONS = 6
/** How many viewport heights of scroll drive the horizontal movement (lower = less scroll needed to see next section) */
const HORIZONTAL_SCROLL_HEIGHT = 4
/** Extra vh at the end so the last section stays fully visible before the footer */
const HORIZONTAL_ZONE_BUFFER_VH = 2.5

export default function Home() {
  const [scrollProgress, setScrollProgress] = useState(0)
  const horizontalRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    const handleScroll = () => {
      const { innerHeight: vh, scrollY } = window
      const triggerStart = vh
      const triggerEnd = vh + vh * HORIZONTAL_SCROLL_HEIGHT
      if (scrollY <= triggerStart) {
        setScrollProgress(0)
        return
      }
      if (scrollY >= triggerEnd) {
        setScrollProgress(1)
        return
      }
      const progress = (scrollY - triggerStart) / (triggerEnd - triggerStart)
      setScrollProgress(progress)
    }

    handleScroll()
    window.addEventListener('scroll', handleScroll, { passive: true })
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  useEffect(() => {
    const sections =
      document.querySelectorAll<HTMLElement>('[data-story-section]')
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.setAttribute('data-visible', 'true')
            observer.unobserve(entry.target)
          }
        })
      },
      { threshold: 0.2, rootMargin: '0px 0px -10% 0px' }
    )
    sections.forEach((section) => observer.observe(section))
    return () => observer.disconnect()
  }, [])

  const translateX = -scrollProgress * (STORY_SECTIONS - 1) * 100

  return (
    <PageLayout>
      {/* Hero - scroll down through this */}
      <section className="relative h-screen w-full flex items-center justify-center overflow-hidden">
        <div className="text-center space-y-12">
          <h1 className="text-6xl md:text-7xl font-rouge tracking-wide animate-crack font-semibold">
            Xuji
          </h1>
          <p className="text-xl tracking-widest font-light opacity-90">
            scroll down
          </p>
          <div className="flex flex-col items-center gap-3">
            <div className="w-0.5 h-12 bg-foreground/60 animate-pulse" />
            <div className="text-sm opacity-60 tracking-tight">—</div>
          </div>
        </div>
      </section>

      {/* Horizontal scroll zone: sticky container, content slides right as you scroll. Buffer so last section stays fully visible before footer. */}
      <div
        ref={horizontalRef}
        style={{
          height: `${(HORIZONTAL_SCROLL_HEIGHT + HORIZONTAL_ZONE_BUFFER_VH) * 100}vh`,
        }}
        className="relative"
      >
        <div className="sticky top-0 h-screen w-full overflow-hidden bg-background">
          <div
            className="flex h-full flex-row will-change-transform"
            style={{
              width: `${STORY_SECTIONS * 100}vw`,
              minWidth: `${STORY_SECTIONS * 100}vw`,
              transform: `translate3d(${translateX}vw, 0, 0)`,
              transition: 'none',
            }}
          >
            <section
              data-story-section
              data-visible="true"
              className="story-section group flex-shrink-0 h-full flex items-center justify-center px-6 overflow-y-auto"
              style={{ width: '100vw', minWidth: '100vw' }}
            >
              <div className="max-w-2xl w-full mx-auto py-8">
                <div className="flex items-center gap-4 mb-6">
                  <span className="text-sm font-mono opacity-70 tracking-widest">
                    01
                  </span>
                  <div className="flex-1 h-px bg-foreground/30" />
                </div>
                <h2 className="font-rouge text-4xl mb-6 tracking-wide font-medium group-hover:opacity-100 transition-opacity duration-300">
                  Who I Am
                </h2>
                <p className="text-sm leading-relaxed opacity-90 text-balance group-hover:opacity-100 transition-opacity duration-300 mb-0">
                  Student-developer at XP Digital. I build things that work, look
                  clean, and feel alive. Code, design, creativity — learned
                  through curiosity, not textbooks.
                </p>
              </div>
            </section>

            <div
              data-story-section
              data-visible="true"
              className="horizontal-panel group flex-shrink-0 h-full flex items-center justify-center px-6 overflow-y-auto"
              style={{ width: '100vw', minWidth: '100vw' }}
            >
              <div className="max-w-2xl w-full mx-auto py-8">
                <StorySection number="02" title="How I Started">
                  <p className="mb-0">
                    Small builds. Random experiments. 2AM debugging sessions. One
                    project at a time, I built myself into this.
                  </p>
                </StorySection>
              </div>
            </div>

            <div
              data-story-section
              data-visible="true"
              className="horizontal-panel group flex-shrink-0 h-full flex items-center justify-center px-6 overflow-y-auto"
              style={{ width: '100vw', minWidth: '100vw' }}
            >
              <div className="max-w-2xl w-full mx-auto py-8">
                <StorySection number="03" title="What I Do Now">
                  <p className="mb-0">
                    Full-stack development with design. AI-powered workflows,
                    automation, modern aesthetics. Building faster, smoother,
                    smarter.
                  </p>
                </StorySection>
              </div>
            </div>

            <div
              data-story-section
              data-visible="true"
              className="horizontal-panel group flex-shrink-0 h-full flex items-center justify-center px-6 overflow-y-auto"
              style={{ width: '100vw', minWidth: '100vw' }}
            >
              <div className="max-w-2xl w-full mx-auto py-8">
                <StorySection number="04" title="My Vision">
                  <p className="mb-0">
                    Master everything I touch. Build projects that outlive me.
                    Open-source. Tools people use. XP Digital global-ready. Not
                    &quot;good enough&quot; — undeniable.
                  </p>
                </StorySection>
              </div>
            </div>

            <div
              data-story-section
              data-visible="true"
              className="horizontal-panel group flex-shrink-0 h-full flex items-center justify-center px-6 overflow-y-auto"
              style={{ width: '100vw', minWidth: '100vw' }}
            >
              <div className="max-w-2xl w-full mx-auto py-8">
                <StorySection number="05" title="Where I'm Going">
                  <p className="mb-0">
                    QUT Mechanical Engineering. Building dev career in parallel.
                    Software, AI, open-source. Becoming a builder who leaves
                    footprints. Still writing the story.
                  </p>
                </StorySection>
              </div>
            </div>

            <div
              data-story-section
              data-visible="true"
              className="horizontal-panel group flex-shrink-0 h-full flex items-center justify-center px-6 overflow-y-auto"
              style={{ width: '100vw', minWidth: '100vw' }}
            >
              <div className="max-w-2xl w-full mx-auto py-8">
                <StorySection number="06" title="Closing Line">
                  <p className="mb-0">
                    A learner. A builder. A creator. Still beginning, pushing
                    forward.
                  </p>
                </StorySection>
              </div>
            </div>
          </div>
        </div>
      </div>
    </PageLayout>
  )
}
